<h2>Admin Dashboard</h2><section class="grid"><div class="card"><h3>Students by Section</h3><?php foreach ($counts as $row): ?><p><?= e(ucfirst($row['school_section'])) ?>: <strong><?= e($row['total']) ?></strong></p><?php endforeach; ?></div><div class="card"><h3>Fee Summary</h3><p>Due: KES <?= number_format($finance['due_total'],2) ?></p><p>Paid: KES <?= number_format($finance['paid_total'],2) ?></p><p>Outstanding: KES <?= number_format($finance['balance_total'],2) ?></p></div><div class="card"><h3>Today's Attendance</h3><?php foreach ($attendance as $row): ?><p><?= e(ucfirst($row['status'])) ?>: <?= e($row['total']) ?></p><?php endforeach; ?></div><div class="card"><h3>Activity</h3><p>Admissions, grades, fee payments and alerts are tracked centrally.</p></div></section>
